def solve(nums, target):
    left, right = 0, len(nums) - 1
    while left < right:
        total = nums[left] + nums[right]
        if total == target:
            return left, right
        if total < target:
            left += 1
        else:
            right -= 1
    return -1, -1

# Additional checks for pitfalls
def solve_with_checks(nums, target):
    if len(nums) < 2:
        return -1, -1  # Handle no-solution case
    seen = {}
    for i, num in enumerate(nums):
        complement = target - num
        if complement in seen:
            return seen[complement], i
        seen[num] = i
    return -1, -1

# Unit tests for critical behaviors
def test_solve():
    assert solve([1, 2, 3, 4, 5], 5) == (0, 3)
    assert solve([1, 2, 3, 4, 5], 10) == (-1, -1)
    assert solve([1, 2, 3, 4, 5], 7) == (1, 3)
    assert solve([1, 2, 3, 4, 5], 8) == (2, 3)

# Adversarial/edge-case tests
def test_solve_with_checks():
    assert solve_with_checks([1, 2, 3, 4, 5], 5) == (0, 3)
    assert solve_with_checks([1, 2, 3, 4, 5], 10) == (-1, -1)
    assert solve_with_checks([1, 2, 3, 4, 5], 7) == (1, 3)
    assert solve_with_checks([1, 2, 3, 4, 5], 8) == (2, 3)
    assert solve_with_checks([1], 1) == (-1, -1)  # No solution case
    assert solve_with_checks([], 1) == (-1, -1)   # No solution case
